SELECT sku,path,brand,name,series,model,properties
FROM products
WHERE (
  brand='Stanley' AND lower(name) LIKE '%screwdriver%hex key%' AND lower(series) LIKE '%workshop%'
)
OR (
  brand='Ryobi' AND lower(name) LIKE '%trimmer%blower%' AND lower(series) LIKE '%battery r18%'
)
OR (
  brand='Carhartt' AND lower(name) LIKE '%work jacket%' AND lower(series) LIKE '%softshell rugged%'
)
OR (
  brand='Bondex' AND lower(name) LIKE '%wood stain%deck oil%' AND lower(series) LIKE '%classic garden%'
)
OR (
  brand='Viega' AND lower(name) LIKE '%valve%connector%' AND lower(series) LIKE '%smartpress sanpress%'
)
OR (
  brand='Legrand' AND lower(name) LIKE '%wiring device%' AND lower(series) LIKE '%valena plexo%'
)
LIMIT 100;

SELECT COUNT(*) AS archived_count FROM payments WHERE basket_archived = 1;
SELECT id, customer_id, store_id, created_at, payment_method_fingerprint, device_fingerprint, observed_lat, observed_lon
FROM payments
WHERE basket_archived = 1
ORDER BY created_at
LIMIT 50;
